#include <bits/stdc++.h>
using namespace std;
long long a,b,c,w[25][25][25];
bool use[25][25][25];
long long dfs(long long a,long long b,long long c){
    if(a>0 && b>0 && c>0 && a<21 && b<21 && c<21 && use[a][b][c])
        return w[a][b][c];
    if(a<=0 || b<=0 || c<=0)
        return 1;
    if(a>20 || b>20 || c>20)
        return dfs(20,20,20);
    if(a<b && b<c){
        if(a>0 && b>0 && c>0 && a<21 && b<21 && c<21)
            use[a][b][c]=1,w[a][b][c]=dfs(a,b-1,c-1)+dfs(a,b,c-1)-dfs(a,b-1,c);
        return dfs(a,b-1,c-1)+dfs(a,b,c-1)-dfs(a,b-1,c);
    }
    if(a>0 && b>0 && c>0 && a<21 && b<21 && c<21)
        use[a][b][c]=1,w[a][b][c]=dfs(a-1,b,c)+dfs(a-1,b-1,c)+dfs(a-1,b,c-1)-dfs(a-1,b-1,c-1);
    return dfs(a-1,b,c)+dfs(a-1,b-1,c)+dfs(a-1,b,c-1)-dfs(a-1,b-1,c-1);
}
int main(){
    while(1){
        scanf("%lld%lld%lld",&a,&b,&c);
        if(a==-1 && b==-1 && c==-1)
            break;
        printf("w(%lld, %lld, %lld) = %lld\n",a,b,c,dfs(a,b,c));
    }
    return 0;
}
